mapper.select:
SELECT d.id, d.user_id AS userId, u.nick_name AS userName, d.title, d.description, d.type, d.hospital_id AS hospitalId, h.hospital_name AS hospitalName, d.department_id AS departmentId, dep.department_name AS departmentName, d.start_date AS startDate, d.end_date AS endDate, d.budget, d.city, d.contact_name AS contactName, d.contact_phone AS contactPhone, d.requirements, d.status, d.refresh_time AS refreshTime, d.create_time AS createTime FROM user_demand d LEFT JOIN user_user u ON u.id = d.user_id LEFT JOIN medical_hospital h ON h.id = d.hospital_id LEFT JOIN medical_department dep ON dep.id = d.department_id
AND d.user_id = #{q.userId}
AND d.status = #{q.status}
AND d.type = #{q.type}
AND d.city = #{q.city}
AND d.budget >= #{q.minBudget}
AND d.budget <= #{q.maxBudget}
AND d.start_date >= #{q.startDate}
AND d.end_date <= #{q.endDate}
ORDER BY d.refresh_time DESC, d.create_time DESC
